import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.*;

@Service
public class FeatureFlagService {
    private int rolloutPercent = 0;  // Start at 0: all traffic on legacy
    private final Set<String> betaMerchants = new HashSet<>(Set.of(
        "MRC-BETA-001", "MRC-BETA-002", "MRC-INTERNAL"));

    public boolean isEnabled(String merchantId) {
        // Beta merchants: always on new service
        if (betaMerchants.contains(merchantId)) return true;
        // Percentage rollout: deterministic hash (same merchant → same system)
        return Math.abs(merchantId.hashCode()) % 100 < rolloutPercent;
    }

    public void setRolloutPercent(int pct) {
        if (pct < 0 || pct > 100) throw new IllegalArgumentException("Rollout % must be 0-100");
        rolloutPercent = pct;
    }

    public int getRolloutPercent() { return rolloutPercent; }

    public void addBetaMerchant(String merchantId) { betaMerchants.add(merchantId); }
}

@SpringBootTest
class FeatureFlagTest {
    @Autowired FeatureFlagService flags;

    @Test void betaMerchant_alwaysEnabled(){
        flags.setRolloutPercent(0); // no general rollout
        assertTrue(flags.isEnabled("MRC-BETA-001")); // beta always on
    }
    @Test void rollout0_allDisabled(){
        flags.setRolloutPercent(0);
        // Non-beta merchant: never enabled at 0%
        assertFalse(flags.isEnabled("MRC-NON-BETA-ZZZZZ"));
    }
    @Test void rollout100_allEnabled(){
        flags.setRolloutPercent(100);
        assertTrue(flags.isEnabled("MRC-ANY-MERCHANT-XYZ"));
    }
}

