@Component
public class StranglerFigFilter extends OncePerRequestFilter {
    private final FeatureFlagService flags;
    // In production: inject WebClient for new order service

    StranglerFigFilter(FeatureFlagService f) { flags = f; }

    @Override
    protected void doFilterInternal(HttpServletRequest req, HttpServletResponse res,
                                    FilterChain chain) throws IOException, ServletException {
        String path = req.getRequestURI();
        String merchantId = req.getHeader("X-Merchant-Id");

        if (path.startsWith("/api/orders") && merchantId != null) {
            if (flags.isEnabled(merchantId)) {
                // Route to NEW microservice:
                routeToNewService(req, res);
                return;  // Don't continue to legacy chain
            }
        }
        // Default: legacy system (existing Spring controllers)
        chain.doFilter(req, res);
    }

    private void routeToNewService(HttpServletRequest req, HttpServletResponse res)
            throws IOException {
        // In production: forward via WebClient to http://new-order-service/api/orders
        // For demo:
        res.setStatus(200);
        res.setContentType("application/json");
        res.getWriter().write("{\"source\":\"new-service\",\"status\":\"routed\"}");
    }

    boolean wouldRouteToNew(String merchantId) {
        return flags.isEnabled(merchantId);
    }
}

@SpringBootTest
class StranglerFigFilterTest {
    @Autowired StranglerFigFilter filter;
    @Autowired FeatureFlagService flags;

    @Test void legacyPath_whenFlagDisabled(){
        flags.setRolloutPercent(0);
        assertFalse(filter.wouldRouteToNew("MRC-REGULAR-MERCHANT"));
    }
    @Test void newServicePath_whenBeta(){
        assertTrue(filter.wouldRouteToNew("MRC-BETA-001")); // beta always on
    }
}

import org.springframework.stereotype.*;
import io.micrometer.core.instrument.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import org.slf4j.*;
import java.util.function.Supplier;

@Service
public class DarkLaunchService<T> {
    private static final Logger log = LoggerFactory.getLogger(DarkLaunchService.class);
    private final MeterRegistry metrics;

    DarkLaunchService(MeterRegistry m) { metrics = m; }

    public T execute(String operationName, Supplier<T> legacy, Supplier<T> newImpl) {
        // Execute legacy (user sees this result):
        T legacyResult = legacy.get();

        // Shadow execute new implementation:
        try {
            T newResult = newImpl.get();
            // Compare outputs:
            if (!legacyResult.equals(newResult)) {
                log.warn("[DARK LAUNCH MISMATCH] op={} legacy={} new={}",
                    operationName, legacyResult, newResult);
                Counter.builder("dark.launch.mismatch")
                    .tag("operation", operationName)
                    .register(metrics).increment();
            } else {
                Counter.builder("dark.launch.match")
                    .tag("operation", operationName)
                    .register(metrics).increment();
            }
        } catch (Exception e) {
            log.error("[DARK LAUNCH ERROR] op={} error={}", operationName, e.getMessage());
            Counter.builder("dark.launch.error")
                .tag("operation", operationName)
                .register(metrics).increment();
        }

        return legacyResult; // ALWAYS return legacy result to user
    }
}

@SpringBootTest
class DarkLaunchTest {
    @Autowired DarkLaunchService<String> svc;
    @Autowired MeterRegistry metrics;

    @Test void sameOutput_noMismatch(){
        String result=svc.execute("order-create",
            ()->"ORD-001",
            ()->"ORD-001"); // same output
        assertEquals("ORD-001",result);
        assertEquals(0.0,metrics.counter("dark.launch.mismatch","operation","order-create").count());
    }
    @Test void diffOutput_mismatchRecorded(){
        svc.execute("order-create2",
            ()->"ORD-LEGACY-001",
            ()->"ORD-NEW-999"); // different output
        assertEquals(1.0,metrics.counter("dark.launch.mismatch","operation","order-create2").count());
    }
}

import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

public enum MigrationPhase {
    DARK_LAUNCH(0),
    BETA_1_PERCENT(1),
    ROLLOUT_10(10),
    ROLLOUT_50(50),
    FULLY_MIGRATED(100);

    public final int rolloutPercent;
    MigrationPhase(int p) { rolloutPercent = p; }
}

@Service
public class MigrationPhaseController {
    private MigrationPhase current = MigrationPhase.DARK_LAUNCH;
    private static final MigrationPhase[] PHASES = MigrationPhase.values();

    public MigrationPhase getCurrentPhase() { return current; }
    public int getCurrentRolloutPercent() { return current.rolloutPercent; }

    public MigrationPhase advance() {
        int idx = current.ordinal();
        if (idx >= PHASES.length - 1) return current; // Already FULLY_MIGRATED
        current = PHASES[idx + 1];
        return current;
    }

    public MigrationPhase rollback() {
        int idx = current.ordinal();
        if (idx <= 0) return current; // Already DARK_LAUNCH (can't go further back)
        current = PHASES[idx - 1];
        return current;
    }
}

@SpringBootTest
class MigrationPhaseTest {
    @Autowired MigrationPhaseController ctrl;

    @Test void phases_progress_correctly(){
        ctrl.advance(); // BETA_1_PERCENT
        ctrl.advance(); // ROLLOUT_10
        assertEquals(MigrationPhase.ROLLOUT_10, ctrl.getCurrentPhase());
        assertEquals(10, ctrl.getCurrentRolloutPercent());
    }
    @Test void rollback_returns_previous(){
        ctrl.advance(); // BETA
        ctrl.rollback(); // back to DARK_LAUNCH
        assertEquals(MigrationPhase.DARK_LAUNCH, ctrl.getCurrentPhase());
    }
    @Test void fullyMigrated_isTerminal(){
        // Advance to end:
        for(int i=0;i<10;i++) ctrl.advance(); // past FULLY_MIGRATED
        assertEquals(MigrationPhase.FULLY_MIGRATED, ctrl.getCurrentPhase());
        ctrl.advance(); // still FULLY_MIGRATED (can't go beyond)
        assertEquals(MigrationPhase.FULLY_MIGRATED, ctrl.getCurrentPhase());
    }
}

