record OrderContract(
    String orderId,    // required
    String status,     // required: PLACED, FILLED, CANCELLED, FAILED
    BigDecimal amount, // required
    String merchantId  // required
) {
    // Validates the contract:
    void assertValid() {
        assertNotNull(orderId, "orderId is required");
        assertNotNull(status, "status is required");
        assertTrue(Set.of("PLACED","FILLED","CANCELLED","FAILED").contains(status),
            "status must be one of: PLACED, FILLED, CANCELLED, FAILED");
        assertNotNull(amount, "amount is required");
        assertTrue(amount.compareTo(BigDecimal.ZERO) > 0, "amount must be positive");
        assertNotNull(merchantId, "merchantId is required");
    }
}

