@Service
public class MigrationMonitor {
    private final MeterRegistry metrics;
    private final AtomicInteger rolloutPercent = new AtomicInteger(0);

    MigrationMonitor(MeterRegistry m) {
        metrics = m;
        // Gauge: reads rolloutPercent at scrape time
        Gauge.builder("migration.rollout_percent", rolloutPercent, AtomicInteger::get)
            .description("Percentage of traffic on new service")
            .register(metrics);
    }

    public void recordLegacy() {
        metrics.counter("orders.legacy").increment();
    }

    public void recordNew() {
        metrics.counter("orders.new").increment();
    }

    public void recordMismatch(String operation) {
        Counter.builder("migration.mismatch")
            .tag("operation", operation)
            .register(metrics).increment();
    }

    public void setRolloutPercent(int pct) {
        rolloutPercent.set(pct);
    }

    public double getLegacyCount() { return metrics.counter("orders.legacy").count(); }
    public double getNewCount() { return metrics.counter("orders.new").count(); }
}

@SpringBootTest
class MigrationMonitorTest {
    @Autowired MigrationMonitor monitor;
    @Autowired MeterRegistry registry;

    @Test void counters_incrementCorrectly(){
        monitor.recordLegacy();
        monitor.recordLegacy();
        monitor.recordNew();
        assertEquals(2.0, monitor.getLegacyCount());
        assertEquals(1.0, monitor.getNewCount());
    }
    @Test void gauge_readsRolloutPercent(){
        monitor.setRolloutPercent(25);
        double val=registry.get("migration.rollout_percent").gauge().value();
        assertEquals(25.0, val);
    }
}

