    boolean isEnabled(String m){return betas.contains(m)||Math.abs(m.hashCode())%100<pct;}
    void setPct(int p){pct=p;}
}

@Service class FullMigrationMonitor {
    private final MeterRegistry m;
    FullMigrationMonitor(MeterRegistry m){this.m=m;}
    void legacy(){m.counter("orders.legacy").increment();}
    void newSvc(){m.counter("orders.new").increment();}
    void mismatch(){m.counter("migration.mismatch").increment();}
    double legacyCount(){return m.counter("orders.legacy").count();}
    double newCount(){return m.counter("orders.new").count();}
    double mismatchCount(){return m.counter("migration.mismatch").count();}
}

@Service class FullStranglerRouter {
    private final FullFeatureFlag flags;
    private final FullMigrationMonitor mon;
    FullStranglerRouter(FullFeatureFlag f,FullMigrationMonitor m){flags=f;mon=m;}

    public String route(String merchantId,Supplier<String> legacy,Supplier<String> newSvc){
        if(flags.isEnabled(merchantId)){
            mon.newSvc();
            return newSvc.get();
        }
        mon.legacy();
        return legacy.get();
    }

    public String darkLaunch(String merchantId,Supplier<String> legacy,Supplier<String> newSvc){
        String legacyResult=legacy.get();
        try{
            String newResult=newSvc.get();
            if(!legacyResult.equals(newResult)) mon.mismatch();
        }catch(Exception ignored){}
        return legacyResult;
    }
}

@SpringBootTest
