    @Autowired FullFeatureFlag flags;
    @Autowired FullMigrationMonitor mon;
    @Autowired FullStranglerRouter router;

    @Test void routing_respectsFlag(){
        flags.setPct(0);
        String result=router.route("MRC-REGULAR",()->"legacy",()->"new");
        assertEquals("legacy",result);
        String betaResult=router.route("MRC-BETA",()->"legacy",()->"new");
