// DUAL-WRITE STRATEGY:
// During migration: write to BOTH old (MySQL) and new (PostgreSQL) DBs
// Reads: based on rollout phase (from old OR new)
// After migration: write only to new, retire old

@Service
class MockMysqlStore {
    Map<String,String> data=new HashMap<>();
    void save(String id,String val){data.put(id,val);}
    Optional<String> find(String id){return Optional.ofNullable(data.get(id));}
}

@Service
class MockPostgresStore {
    Map<String,String> data=new HashMap<>();
    void save(String id,String val){data.put(id,val);}
    Optional<String> find(String id){return Optional.ofNullable(data.get(id));}
}

@Service
class DataSyncService {
    private final MockMysqlStore mysql;
    private final MockPostgresStore postgres;
    DataSyncService(MockMysqlStore m,MockPostgresStore p){mysql=m;postgres=p;}

    // DUAL-WRITE: write to both during migration
    public void save(String id,String value){
        mysql.save(id,value);
        try{
            postgres.save(id,value); // New DB (may lag or fail)
        }catch(Exception e){
            // Log but don't fail the request (old DB is source of truth)
        }
    }

    // READ: from correct source based on phase
    public Optional<String> find(String id,boolean useNewDb){
        return useNewDb ? postgres.find(id) : mysql.find(id);
    }
}

@SpringBootTest
class DataMigrationTest {
    @Autowired DataSyncService sync;
    @Autowired MockMysqlStore mysql;
    @Autowired MockPostgresStore postgres;

    @Test void dualWrite_savesToBothStores(){
        sync.save("ORD-001","status=PLACED");
        assertTrue(mysql.find("ORD-001").isPresent());
        assertTrue(postgres.find("ORD-001").isPresent());
    }
    @Test void readStrategy_selectsCorrectStore(){
        sync.save("ORD-002","status=FILLED");
        assertEquals("status=FILLED",sync.find("ORD-002",false).get()); // MySQL
        assertEquals("status=FILLED",sync.find("ORD-002",true).get()); // PostgreSQL
    }
}

import org.springframework.stereotype.*;
import io.micrometer.core.instrument.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

@Service
public class HealthGatedRolloutService {
    private final FullFeatureFlag flags;
    private final MeterRegistry metrics;
    private int rollout = 0;
    private double errorRate = 0.0;

    HealthGatedRolloutService(FullFeatureFlag f,MeterRegistry m){flags=f;metrics=m;}

    public void setErrorRate(double rate){this.errorRate=rate;}

    // Advance only if healthy:
    public boolean tryAdvance() {
        if (errorRate > 0.01) { // >1% error rate: don't advance
            return false;
        }
        int next = nextPercent();
        rollout = next;
        flags.setPct(rollout);
        return true;
    }

    // Auto-rollback if unhealthy:
    public boolean checkAndRollback() {
        if (errorRate > 0.02) { // >2%: rollback
            rollout = 0;
            flags.setPct(0);
            Counter.builder("migration.auto_rollback").register(metrics).increment();
            return true; // rolled back
        }
        return false;
    }

    private int nextPercent() {
        return switch(rollout) {
            case 0 -> 1;
            case 1 -> 5;
            case 5 -> 10;
            case 10 -> 25;
            case 25 -> 50;
            case 50 -> 100;
            default -> rollout; // already 100%
        };
    }

    public int getRollout(){return rollout;}
}

@SpringBootTest
class HealthGatedRolloutTest {
    @Autowired HealthGatedRolloutService ctrl;

    @Test void healthy_advances(){
        ctrl.setErrorRate(0.005); // 0.5% errors: healthy
        assertTrue(ctrl.tryAdvance());
        assertEquals(1,ctrl.getRollout()); // advanced to 1%
    }
    @Test void unhealthy_doesntAdvance(){
        ctrl.setErrorRate(0.03); // 3% errors: unhealthy
        assertFalse(ctrl.tryAdvance());
    }
    @Test void errorSpike_autoRollback(){
        ctrl.setErrorRate(0.005);ctrl.tryAdvance(); // advance to 1%
        ctrl.setErrorRate(0.05); // spike to 5%
        assertTrue(ctrl.checkAndRollback());
        assertEquals(0,ctrl.getRollout()); // rolled back to 0%
    }
}

