import org.springframework.stereotype.*;
import io.micrometer.core.instrument.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.*;
import java.util.function.Supplier;

@Service class SFFlag {
    int pct=0; Set<String> betas=new HashSet<>(Set.of("MRC-B"));
    boolean enabled(String m){return betas.contains(m)||Math.abs(m.hashCode())%100<pct;}
    void setPct(int p){pct=p;}
}

@Service class SFMonitor {
    private final MeterRegistry m;
    SFMonitor(MeterRegistry m){this.m=m;}
    void legacy(){m.counter("sf.legacy").increment();}
    void newSvc(){m.counter("sf.new").increment();}
    void mismatch(){m.counter("sf.mismatch").increment();}
    double legacyCnt(){return m.counter("sf.legacy").count();}
    double newCnt(){return m.counter("sf.new").count();}
    double mismatchCnt(){return m.counter("sf.mismatch").count();}
}

@Service class SFRouter {
    private final SFFlag flags; private final SFMonitor mon;
    SFRouter(SFFlag f,SFMonitor m){flags=f;mon=m;}
    String route(String m,Supplier<String> l,Supplier<String> n){
        if(flags.enabled(m)){mon.newSvc();return n.get();}
        mon.legacy();return l.get();
    }
    String dark(Supplier<String> l,Supplier<String> n){
        String lr=l.get();
        try{String nr=n.get();if(!lr.equals(nr))mon.mismatch();}catch(Exception ignored){}
        return lr;
    }
}

@SpringBootTest
class M24T4SynthesisTest {
    @Autowired SFFlag flags;
    @Autowired SFRouter router;
    @Autowired SFMonitor mon;

    @Test void legacyPath_default(){
        flags.setPct(0);
        assertEquals("LEGACY",router.route("MRC-REGULAR",()->"LEGACY",()->"NEW"));
        assertEquals(1.0,mon.legacyCnt());
    }
    @Test void beta_routesToNew(){
        assertEquals("NEW",router.route("MRC-B",()->"LEGACY",()->"NEW"));
    }
    @Test void darkLaunch_mismatch(){
        router.dark(()->"OLD-OUT",()->"NEW-OUT");
        assertEquals(1.0,mon.mismatchCnt());
    }
    @Test void rollout100_allNew(){
        flags.setPct(100);
        assertEquals("NEW",router.route("MRC-ANY",()->"LEGACY",()->"NEW"));
    }
}
